import (
	context "context"
	fern "github.com/multi-url-environment-reference/fern"
	fernclient "github.com/multi-url-environment-reference/fern/client"
	option "github.com/multi-url-environment-reference/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Files.Upload(
	context.TODO(),
	&fern.FilesUploadRequest{
		Name:     "name",
		ParentID: "parent_id",
	},
)

